{"code":"import pandas as pd
import json
import re

# Load data
with open(locals()['var_function-call-17894281087799120001'], 'r') as f:
    books_data = json.load(f)
with open(locals()['var_function-call-10804233732653904371'], 'r') as f:
    reviews_data = json.load(f)

df_books = pd.DataFrame(books_data)
df_reviews = pd.DataFrame(reviews_data)

# Helper function to extract year
def extract_year(text):
    if not isinstance(text, str):
        return None
    # Try pattern: "published ... [Year]"
    match = re.search(r'(?:published|released).*?\b((?:19|20)\d{2})\b', text, re.IGNORECASE)
    if match:
        return int(match.group(1))

    # Try pattern: just a 4-digit year (1900-2023)
    matches = re.findall(r'\b(19\d{2}|20[0-2]\d)\b', text)
    if matches:
        return int(matches[0])
    return None

df_books['year'] = df_books['details'].apply(extract_year)

# ID extraction
def extract_id(text, prefix):
    if not isinstance(text, str):
        return None
    try:
        if text.startswith(prefix):
            return int(text[len(prefix):])
        digits = re.sub(r'\D', '', text)
        if digits:
            return int(digits)
        return None
    except:
        return None

df_books['id_num'] = df_books['book_id'].apply(lambda x: extract_id(x, 'bookid_'))
df_reviews['id_num'] = df_reviews['purchase_id'].apply(lambda x: extract_id(x, 'purchaseid_'))

# Convert to decade
df_books_with_year = df_books.dropna(subset=['year']).copy()
df_books_with_year['decade'] = (df_books_with_year['year'] // 10) * 10
df_books_with_year['decade_str'] = df_books_with_year['decade'].astype(int).astype(str) + 's'

# Merge
merged = pd.merge(df_reviews, df_books_with_year, on='id_num', how='inner')

# Aggregation
decade_stats = merged.groupby('decade_str').agg(
    avg_rating=('rating', 'mean'),
    book_count=('id_num', 'nunique')
).reset_index()

debug_info = {
    "num_books_total": len(df_books),
    "num_books_with_year": len(df_books_with_year),
    "num_reviews": len(df_reviews),
    "num_merged": len(merged),
    "decades_found": decade_stats.to_dict(orient='records')
}

print("__RESULT__:")
print(json.dumps(debug_info))
